#include <stdio.h>
#define MAX_SIZE 1001
char grid[MAX_SIZE][MAX_SIZE];
int dp[MAX_SIZE][MAX_SIZE];
int n;
int solve(int i, int j) {
    if (i < 1 || j < 1 || i > n || j > n) return 0;
    if (dp[i][j] != -1) return dp[i][j];
    dp[i][j] = (grid[i][j] == 'P' ? 1 : 0) + max(max(solve(i - 1, j + 2), solve(i + 1, j + 2)), max(solve(i - 2, j + 1), solve(i + 2, j + 1)));
    return dp[i][j];
}
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        scanf("%d", &n);
        int start_i = -1, start_j = -1;
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= n; j++) {
                scanf(" %c", &grid[i][j]);
                dp[i][j] = -1;
                if (grid[i][j] == 'K') {
                    start_i = i;
                    start_j = j;
                }
            }
        }
        printf("%d\n", solve(start_i, start_j));
    }
    return 0;
}

