    static final int MAX_SIZE = 1001;
    static char[][] grid = new char[MAX_SIZE][MAX_SIZE];
    static int[][] dp = new int[MAX_SIZE][MAX_SIZE];
    static int n;
    public static int solve(int i, int j) {
        if (i < 1 || j < 1 || i > n || j > n) return 0;
        if (dp[i][j] != -1) return dp[i][j];
        dp[i][j] = (grid[i][j] == 'P' ? 1 : 0) + Math.max(Math.max(solve(i - 1, j + 2), solve(i + 1, j + 2)), Math.max(solve(i - 2, j + 1), solve(i + 2, j + 1)));
        return dp[i][j];
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            n = sc.nextInt();
            int start_i = -1, start_j = -1;
            for (int i = 1; i <= n; i++) {
                String s = sc.next();
                for (int j = 1; j <= n; j++) {
                    grid[i][j] = s.charAt(j - 1);
                    dp[i][j] = -1;
                    if (grid[i][j] == 'K') {
                        start_i = i;
                        start_j = j;
                    }
                }
            }
            System.out.println(solve(start_i, start_j));
        }
    }
